const config = {
  "previewFeatures": [],
  "clientVersion": "7.8.0",
  "engineVersion": "3c6e192761c0362d496ed980de936e2f3cebcd3a",
  "activeProvider": "postgresql",
  "inlineSchema": "// ─────────────────────────────────────────────────────────────────────────────\n// Carkhodro — Auto Spare Parts E-Commerce\n// PostgreSQL · Prisma ORM\n// ─────────────────────────────────────────────────────────────────────────────\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma_client\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ─────────────────────────────────────────────────────────────────────────────\n// ENUMS\n// ─────────────────────────────────────────────────────────────────────────────\n\nenum UserRole {\n  RETAIL\n  WHOLESALE\n  ADMIN // full back-office access\n  SUPPORT // read-only order/customer access\n}\n\nenum OrderStatus {\n  PENDING // awaiting payment / confirmation\n  CONFIRMED // payment received, pending warehouse pick\n  PROCESSING // warehouse is packing the order\n  SHIPPED // handed to carrier\n  DELIVERED // confirmed delivery\n  CANCELLED\n  REFUNDED\n}\n\nenum PaymentMethod {\n  ONLINE // IPG redirect\n  COD // cash on delivery\n}\n\nenum PaymentStatus {\n  PENDING\n  PAID\n  FAILED\n  REFUNDED\n}\n\nenum ShippingMethod {\n  STANDARD // post — 3-5 business days\n  EXPRESS // 1-2 business days\n}\n\n// ─────────────────────────────────────────────────────────────────────────────\n// REFERENCE DATA\n// ─────────────────────────────────────────────────────────────────────────────\n\n/// The 31 Iranian provinces — seeded once; never deleted.\nmodel Province {\n  id        Int      @id @default(autoincrement())\n  name      String   @unique\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  cities City[]\n\n  @@map(\"provinces\")\n}\n\n/// Cities nested under a province — seeded from a standard list; admin can add more.\nmodel City {\n  id         Int      @id @default(autoincrement())\n  provinceId Int      @map(\"province_id\")\n  name       String\n  createdAt  DateTime @default(now()) @map(\"created_at\")\n\n  province  Province  @relation(fields: [provinceId], references: [id])\n  addresses Address[]\n\n  @@unique([provinceId, name])\n  @@index([provinceId])\n  @@map(\"cities\")\n}\n\n/// Top-level navigation links — managed by admin; front end caches and revalidates.\nmodel NavLink {\n  id        Int      @id @default(autoincrement())\n  href      String   @unique\n  label     String\n  sortOrder Int      @default(0) @map(\"sort_order\")\n  isActive  Boolean  @default(true) @map(\"is_active\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@map(\"nav_links\")\n}\n\n// ─────────────────────────────────────────────────────────────────────────────\n// AUTHENTICATION\n// ─────────────────────────────────────────────────────────────────────────────\n\nmodel User {\n  id           String    @id @default(cuid())\n  /// Iranian mobile format: 09XXXXXXXXX (11 digits)\n  phoneNumber  String    @unique @map(\"phone_number\")\n  firstName    String    @map(\"first_name\")\n  lastName     String    @map(\"last_name\")\n  role         UserRole  @default(RETAIL)\n  /// Set to true after the first successful OTP verification\n  isVerified   Boolean   @default(false) @map(\"is_verified\")\n  /// Wholesale customers must supply a shop/business name\n  shopName     String?   @map(\"shop_name\")\n  birthDate    DateTime? @map(\"birth_date\")\n  profileImage String?   @map(\"profile_image\")\n  createdAt    DateTime  @default(now()) @map(\"created_at\")\n  updatedAt    DateTime  @updatedAt @map(\"updated_at\")\n\n  addresses    Address[]\n  sessions     Session[]\n  orders       Order[]\n  reviews      Review[]\n  cart         Cart?\n  wishlist     WishlistItem[]\n  compareItems CompareItem[]\n\n  @@index([phoneNumber])\n  @@map(\"users\")\n}\n\n/// One active OTP per phone number — upserted on every send request.\nmodel OtpSession {\n  id          String   @id @default(cuid())\n  phoneNumber String   @unique @map(\"phone_number\")\n  /// Bcrypt-hashed in production; store plain only in dev/test\n  codeHash    String   @map(\"code_hash\")\n  /// Hard cutoff — reject even if code matches after this time\n  expiresAt   DateTime @map(\"expires_at\")\n  /// Count repeated send attempts to enable rate-limiting\n  attempts    Int      @default(0)\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n\n  @@index([phoneNumber])\n  @@map(\"otp_sessions\")\n}\n\n/// Server-issued session token — created after OTP is consumed.\nmodel Session {\n  id        String   @id @default(cuid())\n  token     String   @unique\n  userId    String   @map(\"user_id\")\n  expiresAt DateTime @map(\"expires_at\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([expiresAt])\n  @@map(\"sessions\")\n}\n\n/// User delivery addresses — one user may save many; at most one isDefault.\nmodel Address {\n  id         String   @id @default(cuid())\n  userId     String   @map(\"user_id\")\n  cityId     Int      @map(\"city_id\")\n  street     String\n  postalCode String   @map(\"postal_code\")\n  isDefault  Boolean  @default(false) @map(\"is_default\")\n  createdAt  DateTime @default(now()) @map(\"created_at\")\n  updatedAt  DateTime @updatedAt @map(\"updated_at\")\n\n  user   User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  city   City    @relation(fields: [cityId], references: [id])\n  orders Order[]\n\n  @@index([userId])\n  @@index([cityId])\n  @@map(\"addresses\")\n}\n\n// ─────────────────────────────────────────────────────────────────────────────\n// CATALOGUE — CAR TAXONOMY\n// ─────────────────────────────────────────────────────────────────────────────\n\n/// Automobile manufacturers: ایران‌خودرو, سایپا, تویوتا, …\nmodel CarBrand {\n  id           Int      @id @default(autoincrement())\n  name         String   @unique\n  /// URL-safe slug, e.g. \"iran-khodro\"\n  slug         String   @unique\n  logoImage    String?  @map(\"logo_image\")\n  /// Denormalized counter — refreshed by a background job or DB trigger\n  productCount Int      @default(0) @map(\"product_count\")\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n  updatedAt    DateTime @updatedAt @map(\"updated_at\")\n\n  carModels CarModel[]\n\n  @@map(\"car_brands\")\n}\n\n/// Specific car models — FK carBrandId → car_brands.id\nmodel CarModel {\n  id         Int      @id @default(autoincrement())\n  carBrandId Int      @map(\"car_brand_id\")\n  name       String\n  /// Gregorian year production began (null = unknown)\n  yearStart  Int?     @map(\"year_start\")\n  /// Gregorian year production ended (null = still in production)\n  yearEnd    Int?     @map(\"year_end\")\n  image      String?\n  createdAt  DateTime @default(now()) @map(\"created_at\")\n  updatedAt  DateTime @updatedAt @map(\"updated_at\")\n\n  carBrand        CarBrand               @relation(fields: [carBrandId], references: [id])\n  compatibilities ProductCompatibility[]\n\n  @@index([carBrandId])\n  @@map(\"car_models\")\n}\n\n// ─────────────────────────────────────────────────────────────────────────────\n// CATALOGUE — PARTS\n// ─────────────────────────────────────────────────────────────────────────────\n\n/// Spare-parts suppliers / manufacturers: بوش, NGK, ایساکو, …\n/// Distinct from CarBrand — a Bosch brake pad fits a Toyota, not made by Toyota.\nmodel PartsBrand {\n  id        Int      @id @default(autoincrement())\n  name      String   @unique\n  logoImage String?  @map(\"logo_image\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  products Product[]\n\n  @@map(\"parts_brands\")\n}\n\n/// Product category: موتور و قطعات, ترمز و تعلیق, برق و روشنایی, …\nmodel Category {\n  id           Int      @id @default(autoincrement())\n  /// URL / filter slug, e.g. \"engine\", \"brake\"\n  key          String   @unique\n  name         String\n  image        String   @default(\"/logo.png\")\n  sortOrder    Int      @default(0) @map(\"sort_order\")\n  /// Denormalized counter — refreshed by a background job or DB trigger\n  productCount Int      @default(0) @map(\"product_count\")\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n  updatedAt    DateTime @updatedAt @map(\"updated_at\")\n\n  products Product[]\n\n  @@map(\"categories\")\n}\n\n// ─────────────────────────────────────────────────────────────────────────────\n// PRODUCT\n// ─────────────────────────────────────────────────────────────────────────────\n\nmodel Product {\n  id           String @id @default(cuid())\n  /// Human-readable part number, e.g. \"BSH-ENG-206-001\"\n  sku          String @unique\n  name         String\n  partsBrandId Int    @map(\"parts_brand_id\")\n  categoryId   Int    @map(\"category_id\")\n\n  // ── Pricing ────────────────────────────────────────────────────────────────\n  /// Live retail price in Iranian Rial — synced from accountancy API\n  basePrice            BigInt  @map(\"base_price\")\n  /// Percentage deducted for WHOLESALE role users (0–100).\n  /// Wholesale price = basePrice × (1 − wholesaleDiscountPct / 100)\n  wholesaleDiscountPct Decimal @default(0) @map(\"wholesale_discount_pct\") @db.Decimal(5, 2)\n  /// Crossed-out \"was\" price shown in the UI — synced from accountancy API\n  oldPrice             BigInt? @map(\"old_price\")\n  isOffer              Boolean @default(false) @map(\"is_offer\")\n\n  // ── External accounting / ERP sync ────────────────────────────────────────\n  /// Primary key in the external accountancy system.\n  /// Nullable until first sync — product must not go live until populated.\n  accountancyId String?   @unique @map(\"accountancy_id\")\n  /// Timestamp of the last successful price + stock pull from the external API\n  lastSyncedAt  DateTime? @map(\"last_synced_at\")\n\n  // ── Inventory — synced from accountancy API ───────────────────────────────\n  stock Int @default(0)\n\n  // ── Physical / logistics details (managed by local admin) ─────────────────\n  warranty       String?\n  /// Country of origin, e.g. \"آلمان\", \"ژاپن\", \"ایران\"\n  origin         String?\n  /// Units per retail pack (e.g. spark plugs come in sets of 4)\n  packQuantity   Int     @default(1) @map(\"pack_quantity\")\n  /// Retail packs per master carton — for wholesale order sizing\n  cartonQuantity Int     @default(1) @map(\"carton_quantity\")\n  /// true = OEM / genuine part; false = aftermarket\n  isOriginal     Boolean @default(true) @map(\"is_original\")\n\n  // ── Content (managed by local admin) ──────────────────────────────────────\n  mainImage   String? @map(\"main_image\")\n  description String? @db.Text\n\n  // ── Analytics ──────────────────────────────────────────────────────────────\n  viewCount   Int     @default(0) @map(\"view_count\")\n  saleCount   Int     @default(0) @map(\"sale_count\")\n  /// Denormalized average star rating (1.00–5.00) — recomputed on each new review\n  ratingAvg   Decimal @default(0) @map(\"rating_avg\") @db.Decimal(3, 2)\n  reviewCount Int     @default(0) @map(\"review_count\")\n\n  isActive  Boolean  @default(true) @map(\"is_active\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  partsBrand      PartsBrand             @relation(fields: [partsBrandId], references: [id])\n  category        Category               @relation(fields: [categoryId], references: [id])\n  images          ProductImage[]\n  compatibilities ProductCompatibility[]\n  reviews         Review[]\n  cartItems       CartItem[]\n  orderItems      OrderItem[]\n  wishlistedBy    WishlistItem[]\n  comparedBy      CompareItem[]\n\n  @@index([sku])\n  @@index([accountancyId])\n  @@index([categoryId])\n  @@index([partsBrandId])\n  @@index([isActive, isOffer])\n  @@index([saleCount])\n  @@index([viewCount])\n  @@map(\"products\")\n}\n\n/// Additional product gallery images (beyond mainImage).\nmodel ProductImage {\n  id        String  @id @default(cuid())\n  productId String  @map(\"product_id\")\n  url       String\n  alt       String?\n  sortOrder Int     @default(0) @map(\"sort_order\")\n\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n\n  @@index([productId])\n  @@map(\"product_images\")\n}\n\n/// Many-to-many: a spare part can be compatible with multiple car models.\nmodel ProductCompatibility {\n  id         String @id @default(cuid())\n  productId  String @map(\"product_id\")\n  carModelId Int    @map(\"car_model_id\")\n\n  product  Product  @relation(fields: [productId], references: [id], onDelete: Cascade)\n  carModel CarModel @relation(fields: [carModelId], references: [id], onDelete: Cascade)\n\n  @@unique([productId, carModelId])\n  @@index([productId])\n  @@index([carModelId])\n  @@map(\"product_compatibilities\")\n}\n\n/// Customer review and star rating on a product.\nmodel Review {\n  id                 String   @id @default(cuid())\n  productId          String   @map(\"product_id\")\n  /// Nullable — preserves display name even if the user account is deleted\n  userId             String?  @map(\"user_id\")\n  authorName         String   @map(\"author_name\")\n  /// 1–5\n  rating             Int\n  text               String   @db.Text\n  /// true only when the author has a completed order containing this product\n  isVerifiedPurchase Boolean  @default(false) @map(\"is_verified_purchase\")\n  createdAt          DateTime @default(now()) @map(\"created_at\")\n\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n  user    User?   @relation(fields: [userId], references: [id], onDelete: SetNull)\n\n  @@index([productId])\n  @@index([userId])\n  @@map(\"reviews\")\n}\n\n// ─────────────────────────────────────────────────────────────────────────────\n// CART\n// ─────────────────────────────────────────────────────────────────────────────\n\n/// One active cart per user — created lazily on first add-to-cart action.\nmodel Cart {\n  id        String   @id @default(cuid())\n  userId    String   @unique @map(\"user_id\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  user  User       @relation(fields: [userId], references: [id], onDelete: Cascade)\n  items CartItem[]\n\n  @@map(\"carts\")\n}\n\nmodel CartItem {\n  id        String   @id @default(cuid())\n  cartId    String   @map(\"cart_id\")\n  productId String   @map(\"product_id\")\n  quantity  Int      @default(1)\n  addedAt   DateTime @default(now()) @map(\"added_at\")\n\n  cart    Cart    @relation(fields: [cartId], references: [id], onDelete: Cascade)\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n\n  @@unique([cartId, productId])\n  @@index([cartId])\n  @@map(\"cart_items\")\n}\n\n// ─────────────────────────────────────────────────────────────────────────────\n// WISHLIST & COMPARE\n// ─────────────────────────────────────────────────────────────────────────────\n\n/// A product a user has saved for later. Independent of the cart — purely a\n/// per-user bookmark. One row per (user, product); re-adding is a no-op.\nmodel WishlistItem {\n  id        String   @id @default(cuid())\n  userId    String   @map(\"user_id\")\n  productId String   @map(\"product_id\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  user    User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, productId])\n  @@index([userId])\n  @@index([productId])\n  @@map(\"wishlist_items\")\n}\n\n/// A product a user has added to their side-by-side compare list. Same shape as\n/// the wishlist but a separate concern; the app caps the active list size.\nmodel CompareItem {\n  id        String   @id @default(cuid())\n  userId    String   @map(\"user_id\")\n  productId String   @map(\"product_id\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  user    User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, productId])\n  @@index([userId])\n  @@index([productId])\n  @@map(\"compare_items\")\n}\n\n// ─────────────────────────────────────────────────────────────────────────────\n// FAQ\n// ─────────────────────────────────────────────────────────────────────────────\n\n/// Blog posts — authored by admin; displayed on /blog and /blog/[slug].\nmodel Post {\n  id          Int      @id @default(autoincrement())\n  /// URL-safe slug, e.g. \"oil-change-guide\"\n  slug        String   @unique\n  title       String\n  excerpt     String   @db.Text\n  /// HTML body — admin-authored content, never direct user input.\n  body        String   @db.Text\n  coverImage  String   @map(\"cover_image\")\n  author      String\n  tags        String[]\n  /// Estimated read time in minutes\n  readTime    Int      @map(\"read_time\")\n  publishedAt DateTime @map(\"published_at\")\n  isPublished Boolean  @default(true) @map(\"is_published\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  @@index([publishedAt])\n  @@index([isPublished])\n  @@map(\"posts\")\n}\n\n/// Frequently-asked questions — admin-managed; displayed on the /faq page.\nmodel Faq {\n  id        Int      @id @default(autoincrement())\n  question  String\n  answer    String   @db.Text\n  sortOrder Int      @default(0) @map(\"sort_order\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"faqs\")\n}\n\n// ─────────────────────────────────────────────────────────────────────────────\n// ORDERS\n// ─────────────────────────────────────────────────────────────────────────────\n\n/// Shipping methods and their current cost — editable by admin.\nmodel ShippingOption {\n  id          String         @id @default(cuid())\n  method      ShippingMethod @unique\n  label       String\n  description String?\n  cost        BigInt\n  isActive    Boolean        @default(true) @map(\"is_active\")\n  createdAt   DateTime       @default(now()) @map(\"created_at\")\n  updatedAt   DateTime       @updatedAt @map(\"updated_at\")\n\n  orders Order[]\n\n  @@map(\"shipping_options\")\n}\n\nmodel Order {\n  id               String        @id @default(cuid())\n  userId           String        @map(\"user_id\")\n  /// FK kept for history; address data also snapshotted below.\n  addressId        String        @map(\"address_id\")\n  shippingOptionId String        @map(\"shipping_option_id\")\n  status           OrderStatus   @default(PENDING)\n  paymentMethod    PaymentMethod @map(\"payment_method\")\n  paymentStatus    PaymentStatus @default(PENDING) @map(\"payment_status\")\n\n  // ── Snapshotted delivery address ──────────────────────────────────────────\n  // Copied at checkout so later edits to the address row don't affect history.\n  snapshotProvince   String @map(\"snapshot_province\")\n  snapshotCity       String @map(\"snapshot_city\")\n  snapshotStreet     String @map(\"snapshot_street\")\n  snapshotPostalCode String @map(\"snapshot_postal_code\")\n\n  // ── Financials ─────────────────────────────────────────────────────────────\n  subtotal     BigInt @map(\"subtotal\")\n  shippingCost BigInt @map(\"shipping_cost\")\n  /// VAT or other applicable tax collected on this order\n  taxAmount    BigInt @default(0) @map(\"tax_amount\")\n  /// subtotal + shippingCost + taxAmount (stored to prevent drift)\n  totalAmount  BigInt @map(\"total_amount\")\n\n  notes        String?\n  trackingCode String? @map(\"tracking_code\")\n\n  paidAt      DateTime? @map(\"paid_at\")\n  shippedAt   DateTime? @map(\"shipped_at\")\n  deliveredAt DateTime? @map(\"delivered_at\")\n  createdAt   DateTime  @default(now()) @map(\"created_at\")\n  updatedAt   DateTime  @updatedAt @map(\"updated_at\")\n\n  user           User           @relation(fields: [userId], references: [id])\n  address        Address        @relation(fields: [addressId], references: [id])\n  shippingOption ShippingOption @relation(fields: [shippingOptionId], references: [id])\n  items          OrderItem[]\n\n  @@index([userId])\n  @@index([status])\n  @@index([paymentStatus])\n  @@index([createdAt])\n  @@map(\"orders\")\n}\n\nmodel OrderItem {\n  id        String @id @default(cuid())\n  orderId   String @map(\"order_id\")\n  productId String @map(\"product_id\")\n\n  // ── Immutable purchase snapshot ───────────────────────────────────────────\n  productName     String @map(\"product_name\")\n  productSku      String @map(\"product_sku\")\n  /// Exact price charged to this customer — frozen at checkout.\n  /// Reflects the role-based price (retail vs. wholesale) active at that moment.\n  priceAtPurchase BigInt @map(\"price_at_purchase\")\n  /// Tax portion of this line item (e.g. VAT on priceAtPurchase × quantity)\n  taxAmount       BigInt @default(0) @map(\"tax_amount\")\n  quantity        Int\n\n  order   Order   @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  product Product @relation(fields: [productId], references: [id])\n\n  @@index([orderId])\n  @@index([productId])\n  @@map(\"order_items\")\n}\n"
}

